using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;

namespace McpServer;

[McpServerToolType]
public sealed class WeatherTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    // Constructor-injected dependencies — the MCP SDK resolves these from the DI container.
    public WeatherTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool, Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        using var client = _httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var response = await client.GetFromJsonAsync<WeatherResponse>(url, cancellationToken);

        if (response?.Current is null)
            return "No weather data available.";

        var c = response.Current;
        return $"Temperature: {c.Temperature}°C, Wind: {c.WindSpeed} km/h";
    }

    [McpServerTool, Description("Get a multi-day weather forecast for a location.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        [Description("Number of forecast days (1-7)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        days = Math.Clamp(days, 1, 7);
        using var client = _httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";

        var response = await client.GetFromJsonAsync<ForecastResponse>(url, cancellationToken);

        if (response?.Daily is null)
            return "No forecast data available.";

        var lines = response.Daily.Time
            .Select((date, i) =>
                $"{date}: {response.Daily.MinTemp[i]}–{response.Daily.MaxTemp[i]}°C")
            .ToList();

        return string.Join("\n", lines);
    }
}

// --- JSON models for Open-Meteo API ---

public sealed class WeatherResponse
{
    [JsonPropertyName("current")]
    public CurrentWeather? Current { get; set; }
}

public sealed class CurrentWeather
{
    [JsonPropertyName("temperature_2m")]
    public double Temperature { get; set; }

    [JsonPropertyName("wind_speed_10m")]
    public double WindSpeed { get; set; }
}

public sealed class ForecastResponse
{
    [JsonPropertyName("daily")]
    public DailyForecast? Daily { get; set; }
}

public sealed class DailyForecast
{
    [JsonPropertyName("time")]
    public List<string> Time { get; set; } = [];

    [JsonPropertyName("temperature_2m_max")]
    public List<double> MaxTemp { get; set; } = [];

    [JsonPropertyName("temperature_2m_min")]
    public List<double> MinTemp { get; set; } = [];
}

